// NeuConX markdown renderer — complete rewrite
// Assigns to window.marked directly, no IIFE binding issues
window.marked = (function() {

  function escape(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  // Inline renderer: bold, italic, code, links, etc.
  function inline(src) {
    if (!src) return '';
    var out = '';
    var i = 0;
    while (i < src.length) {
      var ch = src[i];
      var rest = src.slice(i);

      // Inline code
      var m = rest.match(/^`([^`]+)`/);
      if (m) { out += '<code>' + escape(m[1]) + '</code>'; i += m[0].length; continue; }

      // Bold+italic ***
      m = rest.match(/^\*{3}([^*\n]+?)\*{3}/);
      if (m) { out += '<strong><em>' + inline(m[1]) + '</em></strong>'; i += m[0].length; continue; }

      // Bold **
      m = rest.match(/^\*{2}([^*\n]+?)\*{2}/);
      if (m) { out += '<strong>' + inline(m[1]) + '</strong>'; i += m[0].length; continue; }

      // Bold __
      m = rest.match(/^_{2}([^_\n]+?)_{2}/);
      if (m) { out += '<strong>' + inline(m[1]) + '</strong>'; i += m[0].length; continue; }

      // Italic *
      m = rest.match(/^\*([^*\n]+?)\*/);
      if (m) { out += '<em>' + inline(m[1]) + '</em>'; i += m[0].length; continue; }

      // Italic _
      m = rest.match(/^_([^_\n]+?)_/);
      if (m) { out += '<em>' + inline(m[1]) + '</em>'; i += m[0].length; continue; }

      // Strikethrough
      m = rest.match(/^~~([^~]+?)~~/);
      if (m) { out += '<del>' + inline(m[1]) + '</del>'; i += m[0].length; continue; }

      // Link
      m = rest.match(/^\[([^\]]+)\]\(([^)]+)\)/);
      if (m) { out += '<a href="' + escape(m[2]) + '" target="_blank" rel="noopener">' + inline(m[1]) + '</a>'; i += m[0].length; continue; }

      // Escape HTML entities
      if (ch === '&') { out += '&amp;'; i++; continue; }
      if (ch === '<') { out += '&lt;'; i++; continue; }
      if (ch === '>') { out += '&gt;'; i++; continue; }

      out += ch;
      i++;
    }
    return out;
  }

  // Split src into top-level block tokens
  function tokenize(src) {
    var tokens = [];
    var lines = src.split('\n');
    var i = 0;

    while (i < lines.length) {
      var line = lines[i];

      // Blank line
      if (!line.trim()) { i++; continue; }

      // Fenced code block
      if (/^```/.test(line)) {
        var lang = line.slice(3).trim();
        var code = [];
        i++;
        while (i < lines.length && !/^```/.test(lines[i])) {
          code.push(lines[i]);
          i++;
        }
        i++; // consume closing ```
        tokens.push({ type: 'code', lang: lang, text: code.join('\n') });
        continue;
      }

      // Heading
      var hm = line.match(/^(#{1,6})\s+(.+)$/);
      if (hm) {
        tokens.push({ type: 'heading', depth: hm[1].length, text: hm[2] });
        i++;
        continue;
      }

      // HR
      if (/^(?:---+|===+|\*\*\*+)\s*$/.test(line.trim())) {
        tokens.push({ type: 'hr' });
        i++;
        continue;
      }

      // Blockquote
      if (/^> /.test(line)) {
        var bqLines = [];
        while (i < lines.length && /^> /.test(lines[i])) {
          bqLines.push(lines[i].slice(2));
          i++;
        }
        tokens.push({ type: 'blockquote', text: bqLines.join('\n') });
        continue;
      }

      // Unordered list
      if (/^[\-\*\+] /.test(line)) {
        var items = [];
        while (i < lines.length && /^[\-\*\+] /.test(lines[i])) {
          items.push(lines[i].replace(/^[\-\*\+] /, ''));
          i++;
        }
        tokens.push({ type: 'ul', items: items });
        continue;
      }

      // Ordered list
      if (/^\d+[\.\)] /.test(line)) {
        var oitems = [];
        while (i < lines.length && /^\d+[\.\)] /.test(lines[i])) {
          oitems.push(lines[i].replace(/^\d+[\.\)] /, ''));
          i++;
        }
        tokens.push({ type: 'ol', items: oitems });
        continue;
      }

      // Table (header | separator | rows)
      if (/\|/.test(line) && i + 1 < lines.length && /\|[\s\-:]+\|/.test(lines[i+1])) {
        var headers = lines[i].split('|').map(function(c){return c.trim();}).filter(Boolean);
        i += 2; // skip header + separator
        var rows = [];
        while (i < lines.length && /\|/.test(lines[i]) && lines[i].trim()) {
          rows.push(lines[i].split('|').map(function(c){return c.trim();}).filter(Boolean));
          i++;
        }
        tokens.push({ type: 'table', headers: headers, rows: rows });
        continue;
      }

      // Paragraph — collect until blank line or block element
      var pLines = [];
      while (i < lines.length && lines[i].trim() &&
             !/^#{1,6} /.test(lines[i]) &&
             !/^```/.test(lines[i]) &&
             !/^[\-\*\+] /.test(lines[i]) &&
             !/^\d+[\.\)] /.test(lines[i]) &&
             !/^> /.test(lines[i]) &&
             !/^(?:---+|===+|\*\*\*+)\s*$/.test(lines[i].trim())) {
        pLines.push(lines[i]);
        i++;
      }
      if (pLines.length) {
        tokens.push({ type: 'paragraph', text: pLines.join('\n') });
      }
    }
    return tokens;
  }

  // Render tokens to HTML
  function render(tokens) {
    return tokens.map(function(tok) {
      switch (tok.type) {
        case 'code':
          return '<pre><code' + (tok.lang ? ' class="language-' + escape(tok.lang) + '"' : '') + '>' +
                 escape(tok.text) + '</code></pre>';

        case 'heading':
          return '<h' + tok.depth + '>' + inline(tok.text) + '</h' + tok.depth + '>';

        case 'hr':
          return '<hr>';

        case 'blockquote':
          return '<blockquote>' + render(tokenize(tok.text)) + '</blockquote>';

        case 'ul':
          return '<ul>' + tok.items.map(function(item) {
            return '<li>' + inline(item) + '</li>';
          }).join('') + '</ul>';

        case 'ol':
          return '<ol>' + tok.items.map(function(item) {
            return '<li>' + inline(item) + '</li>';
          }).join('') + '</ol>';

        case 'table':
          var thead = '<thead><tr>' + tok.headers.map(function(h) {
            return '<th>' + inline(h) + '</th>';
          }).join('') + '</tr></thead>';
          var tbody = '<tbody>' + tok.rows.map(function(row) {
            return '<tr>' + row.map(function(cell) {
              return '<td>' + inline(cell) + '</td>';
            }).join('') + '</tr>';
          }).join('') + '</tbody>';
          return '<table>' + thead + tbody + '</table>';

        case 'paragraph':
          // Paragraphs: single newline = <br>, render inline
          var text = tok.text.split('\n').map(function(line) {
            return inline(line);
          }).join('<br>');
          return '<p>' + text + '</p>';

        default:
          return '';
      }
    }).join('\n');
  }

  function marked(src) {
    if (!src) return '';
    // Normalize line endings
    src = src.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
    var tokens = tokenize(src);
    return render(tokens);
  }

  marked.parse = marked;
  marked.setOptions = function() {};
  return marked;

})();